-- ============================================================================
-- ProfBaza — Demo seed data (migration 003)
-- Generated from the original TS seeds (portalSeed.ts / newsSeed.ts) via
-- `node api/migrations/export_seed.mjs` + `php api/migrations/import_seed.php`,
-- then dumped here so the demo dataset can be restored with plain SQL:
--
--   mysql -u root profbaza_api < api/migrations/003_seed_demo_data.sql
--
-- Re-runnable: clears demo data first. Real (numeric-public_id) users are kept.
-- Demo users log in with their email + password `password`.
-- ============================================================================
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

DELETE FROM `notification_dismissals`; DELETE FROM `notification_roles`; DELETE FROM `notification_users`; DELETE FROM `notifications`;
DELETE FROM `support_attachments`; DELETE FROM `support_tickets`;
DELETE FROM `news_submissions`; DELETE FROM `news_gallery`; DELETE FROM `news_sources`; DELETE FROM `news_tags`; DELETE FROM `news_specialty_tags`; DELETE FROM `news`;
DELETE FROM `document_access_users`; DELETE FROM `document_access_subjects`; DELETE FROM `document_access_tags`; DELETE FROM `document_access_roles`; DELETE FROM `documents`; DELETE FROM `sections`;
DELETE FROM `join_requests`; DELETE FROM `invite_codes`; DELETE FROM `org_creation_requests`;
DELETE FROM `membership_specialty_tags`; DELETE FROM `memberships`; DELETE FROM `org_specialty_tags`; DELETE FROM `organizations`;
DELETE FROM `user_favorites`; DELETE FROM `user_specialty_tags`; DELETE FROM `specialty_tags`;
DELETE FROM `incidents`; DELETE FROM `knowledge_articles`; DELETE FROM `cabinet_entries`;
DELETE FROM `users` WHERE `public_id` LIKE 'u-%';

